pub fn count_words(text: &str) -> usize {
    text.split_whitespace().count()
}

pub fn describe(text: &str) -> String {
    todo!()
}

pub fn summarize_all(notes: Vec<&str>) -> Vec<String> {
    let mut summaries = Vec::new();

    for note in notes {
        summaries.push(describe(note));
    }

    summaries
}

use note_description_lab::{describe, summarize_all};

#[test]
fn describes_empty_text() {
    assert_eq!(describe(""), "No words");
}

#[test]
fn describes_word_count() {
    assert_eq!(describe("learn cargo today"), "3 words");
}

#[test]
fn summarizes_a_vector() {
    let notes = vec!["learn cargo", "", "read errors"];
    assert_eq!(summarize_all(notes), vec!["2 words", "No words", "2 words"]);
}
